Thought: I need to create a JavaScript implementation that parses HTML to extract and categorize URLs (images, scripts, CSS, hyperlinks), handles relative-to-absolute conversion using a base URL, and includes error handling for malformed URLs. I will use `jsdom` for HTML parsing and the native `url` module for URL resolution. I'll write the code to a file named `extractor.js` and then verify it with a test script.
<code>
code = "const { JSDOM } = require('jsdom');
const { URL } = require('url');

function buildAbsoluteUrl(relativeUrl, base) {
    try {
        return new URL(relativeUrl, base).href;
    } catch (e) {
        throw new Error(`Malformed URL: ${relativeUrl}`);
    }
}

async function processHTML(html, base) {
    const dom = new JSDOM(html);
    const document = dom.window.document;

    const resources = {
        images: [],
        scripts: [],
        cssFiles: [],
        hyperlinks: []
    };

    // Images
    const imgElems = document.getElementsByTagName('img');
    for (let img of imgElems) {
        try {
            if (img.src) resources.images.push(buildAbsoluteUrl(img.src, base));
        } catch (err) {
            console.error('An error occurred while processing an image resource url:', err.message);
        }
    }

    // Scripts
    const scriptElems = document.getElementsByTagName('script');
    for (let script of scriptElems) {
        try {
            if (script.src) resources.scripts.push(buildAbsoluteUrl(script.src, base));
        } catch (err) {
            console.error('An error occurred while processing a script resource url:', err.message);
        }
    }

    // CSS Files
    const linkElems = document.getElementsByTagName('link');
    for (let link of linkElems) {
        if (link.rel === 'stylesheet') {
            try {
                if (link.href) resources.cssFiles.push(buildAbsoluteUrl(link.href, base));
            } catch (err) {
                console.error('An error occurred while processing a CSS resource url:', err.message);
            }
        }
    }

    // Hyperlinks
    const aElems = document.getElementsByTagName('a');
    for (let a of aElems) {
        try {
            if (a.href) resources.hyperlinks.push(buildAbsoluteUrl(a.href, base));
        } catch (err) {
            console.error('An error occurred while processing a hyperlink resource url:', err.message);
        }
    }

    return resources;
}

module.exports = { processHTML };
"
