', is_ppp_active() ? 'active' : 'inactive');
    return 0;
}
```

This checks if `/proc/sys/net/ipv4/conf/ppp0` exists, which is created when the ppp interface is up.

> Restarting PPP

You can control the pppd process by sending signals (SIGHUP to restart, SIGTERM to stop). To start the process while maintaining control over the PID, `fork()` and `execl()` are the standard Linux approach. Here is an implementation:

```c
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <signal.h>

void start_ppp() {
    pid_t pid = fork();
    if (pid == 0) {
        execl('/usr/sbin/pppd', 'pppd', NULL); // Ensure path to pppd is correct
    } else if (pid < 0) {
        printf('Error: Unable to fork
');
    }
}

void stop_ppp() {
    system('killall -q pppd');
}

void restart_ppp() {
